with open('C:/books/books.json', encoding='utf-8') as f:
    data = json.load(f)

for book in data:
    if book['id'] in thoughts_map:
        book['thoughts'] = thoughts_map[book['id']]
        print(f'Updated id={book["id"]} — {book["title"]} ({len(book["thoughts"])} thoughts)')

with open('C:/books/books.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print('Done.')
